script.text:
      /* <flatten type="Javascript"> */
function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    gia_nt_sl: '[gia_nt]:=([gia_nt] == 0 ? ([so_luong] != 0 ? ([tien_nt2]/[so_luong]) : 0) : [gia_nt])',
    gia_sl: '[gia]:=([gia] == 0 ? ([so_luong] != 0 ? ([tien2]/[so_luong]) : 0) : [gia])',

    gia_tg: '[gia]:=[gia_nt]*[$ty_gia]',
    tien_nt2_sl: '[tien_nt2]:=[so_luong]*[gia_nt]',
    tien2_sl: '[tien2]:=[so_luong]*[gia]',
    tien2: '[tien2]:=[tien_nt2]*[$ty_gia]',
    ck_nt: '[ck_nt]:=[tien_nt2]*[tl_ck]/100',
    ck_tg: '[ck]:=[ck_nt]*[$ty_gia]',

    dtf_thue_nt: '[thue_nt]:=([tien_nt2] - [ck_nt])*[thue_suat]/100',
    dtf_thue_tl: '[thue]:=([tien2] - [ck])*[thue_suat]/100',
    dtf_thue_tg: '[thue]:=[thue_nt]*[$ty_gia]',

    t_tien_nt2: ['t_tien_nt2', '[tien_nt2]'],
    t_tien2: ['t_tien2', '[tien2]'],
    t_ck_nt: ['t_ck_nt', 'ck_nt'],
    t_ck: ['t_ck', 'ck'],
    dtf_t_thue_nt: ['t_thue_nt', 'thue_nt'],
    dtf_t_thue: ['t_thue', 'thue'],
    t_tt_nt: '[t_tt_nt]:=[t_tien_nt2] - [t_ck_nt]+[t_thue_nt]',
    t_tt: '[t_tt]:=[t_tien2] - [t_ck]+[t_thue]'
  };
  udf$Detail$(g);
}
function scatter$GridVoucherDetail$(g) {reset$GridVoucherDetail(g);}
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
}

function onChange$GridVoucherDetail$Item(o) {
  var f = o.parentForm, g = o.grid, name = o.field.Name;
  switch (name) {
    case 'ma_vt':
      g.request(o, 'Item', 'Item', ['ma_vt']);
      break;
    case 'dvt':
      g.request(o, 'UOM', 'UOM', ['ma_vt', 'dvt']);
      break;
    case 'ma_thue':
      var c = g._getItemValue(o.row, g._getColumnOrder('ma_thue'));
      if ($func.trim(c) != '') {
        g.request(o, 'GetTaxRate', 'GetTaxRate', ['ma_thue']);
      } else {
        g.setItemGridBehavior(o, [['thue_suat', 0, '', false]]);
        g.validExpression(o, [g.$a.dtf_thue_nt, g.$a.dtf_thue_tl], [g.$a.dtf_t_thue_nt, g.$a.dtf_t_thue], [g.$a.t_tt_nt, g.$a.t_tt]);
      }
      break;
    default:
      break;
  }
}
function onChange$GridVoucherDetail$Promotion(o) {
  var g = o.grid, f = g.get_element().parentForm, row = o.row, v = (g._getItemValue(row, g._getColumnOrder('km_yn')) == '1');
  if (v) g.setItemGridBehavior(o, [['ma_thue', '', '', null],['thue_suat', 0, 0, null],['thue_nt', 0, 0, null],['thue', 0, 0, null],['ma_kh2', '', '', null]]);
  on$GridVoucherDetail$AmountChange(o, g, f);
  on$GridVoucherDetail$TaxChange(o, g, f);
}
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'km_yn':
      onChange$GridVoucherDetail$Promotion(o);
      break;
    case 'so_luong':
      g.validExpression(o, [g.$a.tien_nt2_sl, g.$a.tien2, g.$a.ck_nt]);
      on$GridVoucherDetail$AmountChange(o, g, f);
      on$GridVoucherDetail$TaxChange(o, g, f);
      break;
    case 'gia_nt':
      g.validExpression(o, [g.$a.tien_nt2_sl, g.$a.gia_tg, g.$a.tien2, g.$a.ck_nt], null, 'tien_nt2');
      on$GridVoucherDetail$AmountChange(o, g, f);
      on$GridVoucherDetail$TaxChange(o, g, f);
      g.live(o, 'tien_nt2');
      break;
    case 'tien_nt2':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_nt_sl, g.$a.gia_tg]);
      g.validExpression(o, [g.$a.tien2, g.$a.ck_nt]);
      on$GridVoucherDetail$AmountChange(o, g, f);
      on$GridVoucherDetail$TaxChange(o, g, f);
      break;
    case 'gia':
      g.validExpression(o, [g.$a.tien2_sl, g.$a.dtf_thue_tl], [g.$a.t_ck, g.$a.t_tien2, g.$a.dtf_t_thue], [g.$a.t_tt], 'tien2');
      break;
    case 'tien2':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_sl]);
      g.validExpression(o, [g.$a.dtf_thue_tl], [g.$a.t_ck, g.$a.t_tien2, g.$a.dtf_t_thue], [g.$a.t_tt]);
      break;
    case 'tl_ck':
      g.validExpression(o, [g.$a.ck_nt, g.$a.ck_tg], [g.$a.t_tien_nt2, g.$a.t_tien2, g.$a.t_ck_nt, g.$a.t_ck], null, 'ck_nt');
      on$GridVoucherDetail$AmountChange(o, g, f);
      on$GridVoucherDetail$TaxChange(o, g, f);
      break;
    case 'ck_nt':
      g.validExpression(o, [g.$a.ck_tg], [g.$a.t_ck_nt, g.$a.t_ck], [g.$a.t_tt_nt, g.$a.t_tt]);
      on$GridVoucherDetail$AmountChange(o, g, f);
      on$GridVoucherDetail$TaxChange(o, g, f);
      break;
    case 'ck':
      g.validExpression(o, [g.$a.dtf_thue_tl], [g.$a.t_ck, g.$a.dtf_t_thue], [g.$a.t_tt], 'thue');
      break;
    case 'thue_nt':
      g.validExpression(o, [g.$a.dtf_thue_tg], [g.$a.dtf_t_thue_nt, g.$a.dtf_t_thue], [g.$a.t_tt_nt, g.$a.t_tt]);
      break;
    case 'thue':
      g.validExpression(o, null, [g.$a.dtf_t_thue], [g.$a.t_tt]);
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, id = g.get_id(), f = g.get_element().parentForm;
  switch (action) {
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterInsertRow':
      setDefaultValue$DetailTax$Detail(g, [f._defaultTaxCode, f._defaultTaxRate]);
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'Cancel':
      if (f._action == 'View' || !f.getItemValue('stt_rec_hd')) break;
      var msg = (g._language == 'v' ? 'Bạn có chắc chắn bỏ hóa đơn đã chọn không?' : 'Are you sure you want to remove selected invoice?');
      $message.show(msg, 0, String.format('run$GridVoucherDetail($find(\'{0}\'));', id), String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'Item':
      g.setItemGridBehavior(o, [['dvt', result[0].Value, '', true], ['he_so', result[1].Value, null, null]]);
      break;
    case 'UOM':
      g.setItemGridBehavior(o, [['he_so', result[0].Value, null, null]]);
      break;
    case 'GetTaxRate':
      var r = result[0].Value;
      if (g._getItemValue(o.row, g._getColumnOrder('thue_suat')) != r) {
        g.setItemGridBehavior(o, [['thue_suat', result[0].Value, '', null]]);
        g.validExpression(o, [g.$a.dtf_thue_nt, g.$a.dtf_thue_tl], [g.$a.dtf_t_thue_nt, g.$a.dtf_t_thue], [g.$a.t_tt_nt, g.$a.t_tt]);
      }
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$AmountChange(o, g, f) {
  g.executeAggregate([g.$a.t_tien_nt2, g.$a.t_tien2, g.$a.t_ck_nt, g.$a.t_ck]);
}
function on$GridVoucherDetail$RowChange(g, f) {
  g.executeAggregate([g.$a.t_tien_nt2, g.$a.t_tien2, g.$a.t_ck_nt, g.$a.t_ck, g.$a.dtf_t_thue_nt, g.$a.dtf_t_thue]);
  f.executeExpression([g.$a.t_tt_nt, g.$a.t_tt]);
}
function on$GridVoucherDetail$TaxChange(o, g, f) {
  g.validExpression(o, [g.$a.dtf_thue_nt, g.$a.dtf_thue_tl], [g.$a.dtf_t_thue_nt, g.$a.dtf_t_thue], [g.$a.t_tt_nt, g.$a.t_tt]);
}
function run$GridVoucherDetail(g) {
  var f = g.get_element().parentForm;
  f.setItemValues('stt_rec_hd, ma_ct_hd, ma_kh_hd, so_ct_hd, so_seri_hd, ngay_ct_hd, so_hd_goc, mau_hd_goc, ky_hieu_hd_goc, ly_do_dc, so_bb, ngay_bb', ['', '', '', '', null, '', '', '', '', '', null]);
  g._rows = [];
  g._rowCount = 0;
  g._render();
  reset$GridVoucherDetail(g);
}
function reset$GridVoucherDetail(g) {
  var o = g.get_toolbarButton('Search'), f = g.get_element().parentForm;
  if (!o._$addHandler) {
    o.onclick = function() {
      if (!g.get_element().parentForm.validFields('ngay_lct, ma_kh')) return false;
      g.executeCommand({commandName:'Search', commandArgument:'0'});
    }
    o._$addHandler = true;
  }
  on$GridVoucherDetail$RowChange(g, f);
}
function setDefaultValue$DetailTax$Detail(g, a, r, force){
  if (!a || $func.trim(a[0]) == '') return;
  if (!r) r = g._rowCount;
  if ((r > 0) && (force || g._getItemValue(r, g._getColumnOrder('ma_thue')) == '')) {
    var columns = ['ma_thue', 'thue_suat'], km_yn = 0;
    if (g._getColumnOrder('km_yn') >= 0) km_yn = g._getItemValue(r, g._getColumnOrder('km_yn'));
    for (var i = 0; i < columns.length; i++) {
      if (km_yn != '1') g._setItemValue(r, g._getColumnOrder(columns[i]), a[i]);
    }
  }
}
/* </flatten> */
